#include &lt;string.h&gt;
#include &lt;sys/wait.h&gt;

int main() {
    int pipefd[2];

    // 1. We MUST create the pipe BEFORE forking!
    if (pipe(pipefd) == -1) {
        perror("Pipe creation failed");
        exit(EXIT_FAILURE);
    }

    pid_t pid = fork();

    if (pid == 0) {
        // CHILD PROCESS (The Writer)
        close(pipefd[0]); // Close unused read end immediately

        char *msg = "Critical Payload Data\n";
        // Write to the pipe exactly like writing to a file
        write(pipefd[1], msg, strlen(msg));

        // Closing the write end sends an EOF signal to the Parent's read()
        close(pipefd[1]); 
        exit(EXIT_SUCCESS);

    } else {
        // PARENT PROCESS (The Reader)
        close(pipefd[1]); // Close unused write end immediately

        char buffer[1024];
        // read() will block until the Child writes data into the pipe
        ssize_t bytes = read(pipefd[0], buffer, sizeof(buffer));

        if (bytes > 0) {
            buffer[bytes] = '\0';
            printf("Parent received: %s", buffer);
        }

        close(pipefd[0]); // Cleanup
        wait(NULL);       // Reap the zombie child
    }
    return 0;
}

